SELECT id, order_no AS orderNo, customer_name AS customerName, price, remark, address, status, create_time AS createTime FROM trade_order
AND (order_no LIKE CONCAT('%', #{keyword}, '%') OR customer_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY create_time DESC LIMIT #{offset}, #{pageSize}

SELECT id, order_no AS orderNo, customer_name AS customerName, price, remark, address, status, create_time AS createTime
FROM trade_order
WHERE id = #{id}
